  async function prepareSecureSceneTiles(sceneId,assetId,nextConfig){
    const{data:existing=[],error:existingError}=await db.client.from('scene_map_tiles').select('id,asset_id,storage_path').eq('scene_id',sceneId);if(existingError)throw existingError;
    if(assetId&&existing.length&&existing.every(tile=>tile.asset_id===assetId)){await db.client.from('scenes').update({config:{...nextConfig,map_tiled:true}}).eq('id',sceneId);return;}
    if(existing.length){const paths=existing.map(tile=>tile.storage_path);for(let index=0;index<paths.length;index+=100){const{error}=await db.client.storage.from('campaign-media').remove(paths.slice(index,index+100));if(error)throw error;}const{error:deleteError}=await db.client.from('scene_map_tiles').delete().eq('scene_id',sceneId);if(deleteError)throw deleteError;}
    if(!assetId){await db.client.from('scenes').update({config:{...nextConfig,map_tiled:false}}).eq('id',sceneId);return;}
    notice('Preparing private map tiles…');
    const{data:asset,error:assetError}=await db.client.from('campaign_assets').select('storage_path').eq('id',assetId).single();if(assetError)throw assetError;
    const{data:signed,error:signedError}=await db.client.storage.from('campaign-media').createSignedUrl(asset.storage_path,600);if(signedError)throw signedError;
    const response=await fetch(signed.signedUrl);if(!response.ok)throw new Error('The background image could not be loaded for secure tiling.');
    const bitmap=await createImageBitmap(await response.blob()),columns=12,rows=Math.max(1,Math.min(24,Math.round(columns*bitmap.height/bitmap.width))),records=[],uploaded=[];
    const makeTile=async(column,row)=>{const startX=Math.floor(column*bitmap.width/columns),endX=Math.floor((column+1)*bitmap.width/columns),startY=Math.floor(row*bitmap.height/rows),endY=Math.floor((row+1)*bitmap.height/rows),canvas=document.createElement('canvas');canvas.width=Math.max(1,endX-startX);canvas.height=Math.max(1,endY-startY);canvas.getContext('2d').drawImage(bitmap,startX,startY,canvas.width,canvas.height,0,0,canvas.width,canvas.height);const blob=await new Promise((resolve,reject)=>canvas.toBlob(value=>value?resolve(value):reject(new Error('A secure map tile could not be encoded.')),'image/webp',.84)),path=`${campaignId}/map-tiles/${sceneId}/${column}-${row}-${crypto.randomUUID()}.webp`,{error}=await db.client.storage.from('campaign-media').upload(path,blob,{contentType:'image/webp',upsert:false});if(error)throw error;uploaded.push(path);records.push({scene_id:sceneId,asset_id:assetId,tile_column:column,tile_row:row,grid_columns:columns,grid_rows:rows,storage_path:path});};
    try{for(let row=0;row<rows;row+=1){for(let column=0;column<columns;column+=6){await Promise.all(Array.from({length:Math.min(6,columns-column)},(_,offset)=>makeTile(column+offset,row)));}}const{error:insertError}=await db.client.from('scene_map_tiles').insert(records);if(insertError)throw insertError;await db.client.from('scenes').update({config:{...nextConfig,map_tiled:true}}).eq('id',sceneId);}catch(error){for(let index=0;index<uploaded.length;index+=100)await db.client.storage.from('campaign-media').remove(uploaded.slice(index,index+100));throw error;}finally{bitmap.close?.();}
  }
